import{_ as t,o as s,c as r,ai as d}from"./chunks/framework.LYGRWSbL.js";const u=JSON.parse('{"title":"Les verbes modaux","description":"","frontmatter":{"next":{"text":"Module 4 - Parler du temps","link":"../module-4-le-temps/"}},"headers":[],"relativePath":"module-3-quotidien/verbes-modaux.md","filePath":"module-3-quotidien/verbes-modaux.md","lastUpdated":1773298982000}'),a={name:"module-3-quotidien/verbes-modaux.md"};function n(l,e,o,i,c,m){return s(),r("div",null,[...e[0]||(e[0]=[d('<h1 id="les-verbes-modaux" tabindex="-1">Les verbes modaux <a class="header-anchor" href="#les-verbes-modaux" aria-label="Permalink to “Les verbes modaux”">​</a></h1><p><strong>Prérequis :</strong> <a href="./poser-des-questions.html">Poser des questions</a></p><p><strong>Objectif :</strong> utiliser les six verbes modaux pour exprimer la capacite, l&#39;obligation, la permission et la volonte.</p><p>Les verbes modaux (<em>Modalverben</em>) modifient le sens du verbe principal. Ils se conjuguent seuls et repoussent le verbe principal a l&#39;infinitif en fin de phrase.</p><h2 id="les-six-verbes-modaux" tabindex="-1">Les six verbes modaux <a class="header-anchor" href="#les-six-verbes-modaux" aria-label="Permalink to “Les six verbes modaux”">​</a></h2><div class="mt-4 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600">Verbe</th><th class="p-3 text-left font-semibold text-gray-600">Sens principal</th><th class="p-3 text-left font-semibold text-gray-600">Exemple</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3 font-bold text-green-700">können</td><td class="p-3 text-gray-600">pouvoir (capacite)</td><td class="p-3 text-gray-500 italic">Ich kann schwimmen.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-green-700">müssen</td><td class="p-3 text-gray-600">devoir (obligation)</td><td class="p-3 text-gray-500 italic">Ich muss arbeiten.</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold text-green-700">wollen</td><td class="p-3 text-gray-600">vouloir</td><td class="p-3 text-gray-500 italic">Ich will schlafen.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-green-700">dürfen</td><td class="p-3 text-gray-600">avoir le droit de / pouvoir (permission)</td><td class="p-3 text-gray-500 italic">Du darfst kommen.</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold text-green-700">sollen</td><td class="p-3 text-gray-600">être sense faire / devoir (instruction externe)</td><td class="p-3 text-gray-500 italic">Du sollst warten.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-green-700">mögen</td><td class="p-3 text-gray-600">aimer / apprécier</td><td class="p-3 text-gray-500 italic">Ich mag Kaffee.</td></tr></tbody></table></div><h2 id="conjugaison" tabindex="-1">Conjugaison <a class="header-anchor" href="#conjugaison" aria-label="Permalink to “Conjugaison”">​</a></h2><p>Les modaux sont irréguliers. Ils ont une particularité : <em>ich</em> et <em>er/sie/es</em> ont la même forme (sans terminaison).</p><div class="mt-4 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600">Pronom</th><th class="p-3 text-center font-semibold text-green-700">können</th><th class="p-3 text-center font-semibold text-green-700">müssen</th><th class="p-3 text-center font-semibold text-green-700">wollen</th><th class="p-3 text-center font-semibold text-green-700">dürfen</th><th class="p-3 text-center font-semibold text-green-700">sollen</th><th class="p-3 text-center font-semibold text-green-700">mögen</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3 font-medium">ich</td><td class="p-3 text-center">kann</td><td class="p-3 text-center">muss</td><td class="p-3 text-center">will</td><td class="p-3 text-center">darf</td><td class="p-3 text-center">soll</td><td class="p-3 text-center">mag</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-medium">du</td><td class="p-3 text-center">kannst</td><td class="p-3 text-center">musst</td><td class="p-3 text-center">willst</td><td class="p-3 text-center">darfst</td><td class="p-3 text-center">sollst</td><td class="p-3 text-center">magst</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-medium">er/sie/es</td><td class="p-3 text-center">kann</td><td class="p-3 text-center">muss</td><td class="p-3 text-center">will</td><td class="p-3 text-center">darf</td><td class="p-3 text-center">soll</td><td class="p-3 text-center">mag</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-medium">wir</td><td class="p-3 text-center">können</td><td class="p-3 text-center">müssen</td><td class="p-3 text-center">wollen</td><td class="p-3 text-center">dürfen</td><td class="p-3 text-center">sollen</td><td class="p-3 text-center">mögen</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-medium">ihr</td><td class="p-3 text-center">konnt</td><td class="p-3 text-center">musst</td><td class="p-3 text-center">wollt</td><td class="p-3 text-center">durft</td><td class="p-3 text-center">sollt</td><td class="p-3 text-center">mogt</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-medium">sie/Sie</td><td class="p-3 text-center">können</td><td class="p-3 text-center">müssen</td><td class="p-3 text-center">wollen</td><td class="p-3 text-center">dürfen</td><td class="p-3 text-center">sollen</td><td class="p-3 text-center">mögen</td></tr></tbody></table></div><h2 id="la-structure-avec-un-modal" tabindex="-1">La structure avec un modal <a class="header-anchor" href="#la-structure-avec-un-modal" aria-label="Permalink to “La structure avec un modal”">​</a></h2><p>Le modal est conjugue en position 2. Le verbe principal reste a l&#39;<strong>infinitif en fin de phrase</strong>.</p><div class="mt-4 p-4 rounded-xl border border-gray-200"><div class="grid grid-cols-4 gap-2 text-center"><div class="bg-blue-50 border border-blue-200 rounded p-2"><div class="text-xs text-blue-500 font-medium">Sujet</div><div class="font-bold text-blue-800">Ich</div></div><div class="bg-green-50 border border-green-200 rounded p-2"><div class="text-xs text-green-500 font-medium">Modal (pos. 2)</div><div class="font-bold text-green-800">kann</div></div><div class="bg-gray-50 border border-gray-200 rounded p-2"><div class="text-xs text-gray-500 font-medium">Complement</div><div class="font-bold text-gray-700">gut</div></div><div class="bg-orange-50 border border-orange-200 rounded p-2"><div class="text-xs text-orange-500 font-medium">Infinitif (fin)</div><div class="font-bold text-orange-800">kochen.</div></div></div><div class="text-sm text-gray-500 text-center mt-3">Je sais bien cuisiner.</div></div><p>Autres exemples :</p><ul><li><em>Du musst jetzt <strong>schlafen</strong>.</em> - Tu dois dormir maintenant.</li><li><em>Er will nach Berlin <strong>fahren</strong>.</em> - Il veut aller a Berlin.</li><li><em>Wir dürfen hier nicht <strong>parken</strong>.</em> - On n&#39;a pas le droit de se garer ici.</li><li><em>Soll ich das <strong>machen</strong> ?</em> - Je suis sense faire ca ?</li></ul><div class="warning custom-block"><p class="custom-block-title">können vs dürfen - pouvoir n&#39;est pas toujours &quot;können&quot;</p><p><em>Können</em> = capacité physique ou intellectuelle (<em>ich kann schwimmen</em> - je sais nager). <em>Durfen</em> = permission (<em>ich darf hier parken</em> - j&#39;ai le droit de me garer ici). En français, « pouvoir » couvre les deux. En allemand, la distinction est obligatoire.</p></div><h2 id="mochten-voudrais-forme-polie-de-mogen" tabindex="-1">möchten - voudrais (forme polie de mögen) <a class="header-anchor" href="#mochten-voudrais-forme-polie-de-mogen" aria-label="Permalink to “möchten - voudrais (forme polie de mögen)”">​</a></h2><p><em>Möchten</em> est la forme de politesse pour exprimer un souhait, très utilisée pour commander ou demander :</p><table tabindex="0"><thead><tr><th>Pronom</th><th>möchten</th></tr></thead><tbody><tr><td>ich</td><td>möchte</td></tr><tr><td>du</td><td>möchtest</td></tr><tr><td>er/sie/es</td><td>möchte</td></tr><tr><td>wir</td><td>möchten</td></tr><tr><td>ihr</td><td>möchtet</td></tr><tr><td>sie/Sie</td><td>möchten</td></tr></tbody></table><ul><li><em>Ich möchte einen Kaffee.</em> - Je voudrais un cafe.</li><li><em>Wir möchten bitte die Rechnung.</em> - Nous voudrions l&#39;addition, s&#39;il vous plait.</li></ul><div class="tip custom-block"><p class="custom-block-title">möchten est plus poli que wollen</p><p><em>Ich will einen Kaffee</em> est grammaticalement correct mais sonne brusque. En situation réelle, utilisé toujours <em>ich möchte</em> pour commander ou demander quelque chose. C&#39;est l&#39;équivalent de &quot;je voudrais&quot; vs &quot;je veux&quot;.</p></div>',20)])])}const x=t(a,[["render",n]]);export{u as __pageData,x as default};
